80	    const ctx     = await browser.newContext();
81	
82	    async function freshPage() {
83	        // Clear storage so every test starts from a known blank state
84	        await ctx.clearCookies();
85	        const page = await ctx.newPage();
86	        const errors = [];
87	        page.on('pageerror', e => errors.push(e.message));
88	        // Wipe IndexedDB and localStorage before loading
89	        await page.addInitScript(() => {
90	            indexedDB.deleteDatabase('swimlane_journal_v14');
91	            localStorage.clear();
92	        });
93	        return { page, errors };
94	    }
95	
96	    // Loads the app with known state:
97	    //   1. Fresh blank page (storage wiped by freshPage initScript)
98	    //   2. Second initScript sets swimlane_onboarded so onboarding never blocks
99	    //   3. First navigation initialises the app's IDB connection
100	    //   4. Seeded state written into IDB from the page context
101	    //   5. Reload — app boots from the seeded IDB, no onboarding
102	    // items: array of item objects; settings: partial settings override.
103	    // Returns { page, errors, laneId } — page is already loaded and ready.
104	    async function seededPage(items, settings = {}) {
105	        const { page, errors } = await freshPage();
106	        // Runs AFTER freshPage's clear-initScript on every navigation, marking the
107	        // user as onboarded so the modal never blocks test clicks.
108	        await page.addInitScript(() => {
109	            localStorage.setItem('swimlane_onboarded', 'true');
110	        });
111	
112	        await page.goto(FILE_URL);
113	        await page.waitForTimeout(1200);
114	
115	        const laneId = 'test-lane';
116	        const seedState = {
117	            version: 14,
118	            lanes:   [{ id: laneId, title: 'Lane', minimized: false, color: '#6366f1' }],
119	            habits: [], notes: [], projects: [],
120	            habitChecks: {}, diary: {}, focus: {},
121	            items,
122	            settings: { theme: 'dotted', horizonMode: 'all', habitMode: 'streak',
123	                        showAchievements: false, showHorizon: false, habitsMin: false, diaryMin: false,
124	                        ...settings }
125	        };
126	
127	        // Write directly into the IDB that the app already opened.
128	        const writeResult = await page.evaluate(async (stateToSave) => {
