                    const tx = db.transaction('state', 'readwrite');
                    tx.objectStore('state').put(stateToSave, 'appData');
                    tx.oncomplete = () => { db.close(); resolve({ ok: true }); };
                    tx.onerror   = (err) => { db.close(); resolve({ ok: false, err: String(err) }); };
